package vendor

import (
	"errors"
	"fmt"
	"io"
	"slices"

	"github.com/BurntSushi/toml"
	"github.com/purpleclay/go-overlay/internal/mod"
)

const (
	SchemaVersion  = 3
	manifestHeader = "# Generated by govendor. DO NOT EDIT.\n\n"
)

// Manifest represents a govendor.toml file.
type Manifest struct {
	Schema           int                         `toml:"schema"`
	IncludePlatforms []string                    `toml:"include_platforms,omitempty"`
	Workspace        *mod.WorkspaceConfig        `toml:"workspace,omitempty"`
	Tool             mod.ToolConfig              `toml:"tool,omitempty"`
	Exclude          map[string][]string         `toml:"exclude,omitempty"`
	Mod              map[string]mod.ModuleConfig `toml:"mod"`
}

// New builds a Manifest from resolved dependencies. Pass a non-nil workspace
// for workspace (go.work) projects, and a non-nil tool for modules with tool
// directives.
func New(deps []mod.ModuleConfig, includePlatforms []string, workspace *mod.WorkspaceConfig, tool mod.ToolConfig, excludes map[string][]string) *Manifest {
	mods := make(map[string]mod.ModuleConfig, len(deps))
	for _, m := range deps {
		mods[m.Path] = m
	}

	var recorded []string
	if len(includePlatforms) > 0 {
		recorded = make([]string, len(includePlatforms))
		copy(recorded, includePlatforms)
		slices.Sort(recorded)
	}

	return &Manifest{
		Schema:           SchemaVersion,
		IncludePlatforms: recorded,
		Workspace:        workspace,
		Tool:             tool,
		Exclude:          excludes,
		Mod:              mods,
	}
}

// Parse unmarshals a govendor.toml file into a Manifest. The Path field of
// each ModuleConfig is backfilled from its map key, since it is excluded from
// TOML encoding.
func Parse(data []byte) (*Manifest, error) {
	var m Manifest
	if err := toml.Unmarshal(data, &m); err != nil {
		return nil, err
	}
	if err := validateManifest(&m); err != nil {
		return nil, err
	}
	for path, cfg := range m.Mod {
		cfg.Path = path
		m.Mod[path] = cfg
	}
	return &m, nil
}

func validateManifest(m *Manifest) error {
	if m.Schema == 0 {
		return errors.New("govendor.toml: missing required 'schema' field")
	}
	if m.Mod == nil {
		return errors.New("govendor.toml: missing required '[mod]' section")
	}
	if m.Workspace != nil {
		if m.Workspace.Go == "" {
			return errors.New("govendor.toml: [workspace] missing required 'go' field")
		}
		if len(m.Workspace.Modules) == 0 {
			return errors.New("govendor.toml: [workspace] missing required 'modules' field")
		}
	}
	for pkg, cfg := range m.Tool {
		if cfg.Version == "" {
			return fmt.Errorf("govendor.toml: [tool.%q] missing required 'version' field", pkg)
		}
	}
	return nil
}

// WriteTo encodes the manifest as TOML into w.
func (m *Manifest) WriteTo(w io.Writer) (int64, error) {
	cw := &countingWriter{w: w}

	if _, err := io.WriteString(cw, manifestHeader); err != nil {
		return cw.n, err
	}

	if err := toml.NewEncoder(cw).Encode(m); err != nil {
		return cw.n, err
	}

	return cw.n, nil
}

type countingWriter struct {
	w io.Writer
	n int64
}

func (c *countingWriter) Write(p []byte) (int, error) {
	n, err := c.w.Write(p)
	c.n += int64(n)
	return n, err
}
